export function exportToCSV(data, filename = 'export.csv', columns) {
  if (!Array.isArray(data) || data.length === 0) return;

  const escapeCSV = (str) => {
    if (str == null) return '';
    const s = String(str);
    if (s.includes('"') || s.includes(',') || s.includes('\n')) {
      return `"${s.replace(/"/g, '""')}"`;
    }
    return s;
  };

  const formatValue = (val, format) => {
    if (val == null) return '';
    switch (format) {
      case 'currency':
        return formatCurrency(val);
      case 'percent':
        return formatPercent(val);
      case 'number':
        return formatNumber(val);
      case 'date':
        try {
          const d = new Date(val);
          if (isNaN(d)) return '';
          return d.toISOString();
        } catch {
          return '';
        }
      default:
        if (typeof format === 'function') {
          try {
            return format(val);
          } catch {
            return '';
          }
        }
        return String(val);
    }
  };

  let headers = [];
  let keys = [];

  if (Array.isArray(columns) && columns.length > 0) {
    headers = columns.map((col) => col.label || col.key);
    keys = columns.map((col) => col.key);
  } else {
    keys = Object.keys(data[0]);
    headers = keys;
  }

  const csvRows = [];
  csvRows.push(headers.map(escapeCSV).join(','));

  for (const row of data) {
    const rowValues = keys.map((key, i) => {
      const col = columns && columns[i];
      const val = row[key];
      const formatted = col ? formatValue(val, col.format) : val == null ? '' : String(val);
      return escapeCSV(formatted);
    });
    csvRows.push(rowValues.join(','));
  }

  const csvString = csvRows.join('\r\n');
  const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);

  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.style.display = 'none';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

export function exportToJSON(data, filename = 'export.json') {
  if (data == null) return;
  const jsonString = JSON.stringify(data, null, 2);
  const blob = new Blob([jsonString], { type: 'application/json;charset=utf-8;' });
  const url = URL.createObjectURL(blob);

  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.style.display = 'none';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

export async function copyToClipboard(data, format = 'tsv') {
  if (!Array.isArray(data) || data.length === 0) return;

  const keys = Object.keys(data[0]);

  const escapeTSV = (str) => {
    if (str == null) return '';
    const s = String(str);
    return s.replace(/\t/g, ' ').replace(/\n/g, ' ');
  };

  const rows = [];
  rows.push(keys.join('\t'));

  for (const row of data) {
    const rowValues = keys.map((key) => {
      const val = row[key];
      return escapeTSV(val);
    });
    rows.push(rowValues.join('\t'));
  }

  const tsvString = rows.join('\n');

  if (navigator.clipboard && navigator.clipboard.writeText) {
    try {
      await navigator.clipboard.writeText(tsvString);
    } catch {
      fallbackCopyTextToClipboard(tsvString);
    }
  } else {
    fallbackCopyTextToClipboard(tsvString);
  }

  function fallbackCopyTextToClipboard(text) {
    const textArea = document.createElement('textarea');
    textArea.value = text;
    textArea.style.position = 'fixed';
    textArea.style.top = '-9999px';
    document.body.appendChild(textArea);
    textArea.focus();
    textArea.select();
    try {
      document.execCommand('copy');
    } catch {}
    document.body.removeChild(textArea);
  }
}

export function formatCurrency(val, currency = 'USD') {
  if (val == null || isNaN(val)) return '';
  try {
    return new Intl.NumberFormat(undefined, {
      style: 'currency',
      currency,
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(val);
  } catch {
    return val.toFixed(2);
  }
}

export function formatPercent(val, decimals = 2) {
  if (val == null || isNaN(val)) return '';
  try {
    const num = Number(val);
    return `${num.toFixed(decimals)}%`;
  } catch {
    return '';
  }
}

export function formatNumber(val, decimals = 2) {
  if (val == null || isNaN(val)) return '';
  try {
    return Number(val).toLocaleString(undefined, {
      minimumFractionDigits: decimals,
      maximumFractionDigits: decimals,
    });
  } catch {
    return val.toFixed(decimals);
  }
}
